                if m not in seen:
                    out.append(m); seen.add(m)
        while len(out) < 9:
            cand = (0, 0)
            out.append(cand)
            break
        return out[:9]

    scores = observation.get("scores", None)
    self_name = observation.get("self_name", "")
    opp_name = observation.get("opponent_name", "")
    self_score = 0; opp_score = 0
    if isinstance(scores, dict):
